import autogen
from difflib import SequenceMatcher

def detect_output_variance(config_list, task, n_runs=5):
    results = []
    for i in range(n_runs):
        llm_config = {"config_list": config_list, "seed": i}
        agent = autogen.AssistantAgent("analyzer", llm_config=llm_config)
        user_proxy = autogen.UserProxyAgent("user")

        result = user_proxy.initiate_chat(agent, message=task)
        final_output = result.chat_history[-1]['content']
        results.append(final_output)

    # Calculate variance
    variances = []
    for i in range(len(results)):
        for j in range(i+1, len(results)):
            similarity = SequenceMatcher(None, results[i], results[j]).ratio()
            variances.append(1 - similarity)

    avg_variance = sum(variances) / len(variances)
    return {
        'avg_variance': avg_variance,
        'threshold_alert': avg_variance > 0.3,
        'samples': results[:3]
    }

import re
from sklearn.feature_extraction.text import TfidfVectorizer
from sklearn.metrics.pairwise import cosine_similarity

def check_fact_consistency(run_outputs):
    facts = []
    fact_patterns = [r'\d+\.\d+', r'20\d{2}', r'\$[0-9,]+', r'[A-Z][a-z]+ [A-Z][a-z]+']

    for output in run_outputs:
        output_facts = []
        for pattern in fact_patterns:
            matches = re.findall(pattern, output)
            output_facts.extend(matches)
        facts.append(output_facts)

    if len(facts) < 2:
        return {'consistent': True}

    vectorizer = TfidfVectorizer()
    fact_vectors = vectorizer.fit_transform([' '.join(f) for f in facts])
    similarities = cosine_similarity(fact_vectors)

    avg_similarity = np.mean(similarities[np.triu_indices(len(similarities), k=1)])

    return {
        'fact_consistency_score': avg_similarity,
        'inconsistent': avg_similarity < 0.7,
        'fact_samples': [f[:5] for f in facts]
    }

