import json
import autogen
from pydantic import BaseModel, Field

class TaskOutput(BaseModel):
    conclusion: str = Field(..., description="Final answer")
    confidence: float = Field(ge=0, le=1)
    supporting_facts: list[str] = []
    version: str = "1.0"

class ConsistentAgent(autogen.AssistantAgent):
    def __init__(self, *args, **kwargs):
        super().__init__(*args, **kwargs)
        self.output_schema = TaskOutput

    def generate_reply(self, messages, sender, config):
        response = super().generate_reply(messages, sender, config)

        # Enforce structured output
        try:
            parsed = json.loads(response)
            validated = self.output_schema(**parsed)
            return validated.model_dump_json()
        except:
            # Fallback to strict prompt
            return self.enforce_structure(response)

    def enforce_structure(self, text):
        return json.dumps({
            "conclusion": text[:200],
            "confidence": 0.8,
            "supporting_facts": [],
            "version": "1.0"
        })

class DeterministicGroupChatManager(GroupChatManager):
    def __init__(self, agents, max_rounds=5, **kwargs):
        super().__init__(agents, **kwargs)
        self.max_rounds = max_rounds
        self.round = 0
        self.speaker_order = agents[:]

    def select_speaker(self, last_speaker, selector):
        if self.round >= self.max_rounds:
            return None  # Terminate consistently

        if last_speaker is None:
            speaker = self.speaker_order[0]
        else:
            idx = self.speaker_order.index(last_speaker)
            speaker = self.speaker_order[(idx + 1) % len(self.speaker_order)]

        self.round += 1
        return speaker

# Usage
